solution:
class HashMap:
    def __init__(self, size=8):
        self.size = size
        self.buckets = [[] for _ in range(self.size)]

    def _hash(self, key):
        h = 0
        for ch in key:
            h = h * 31 + ord(ch)
        return h % self.size

    def put(self, key, val):
        bucket = self.buckets[self._hash(key)]
        for pair in bucket:
            if pair[0] == key:
                pair[1] = val
                return
        bucket.append([key, val])

    def get(self, key):
        bucket = self.buckets[self._hash(key)]
        for pair in bucket:
            if pair[0] == key:
                return pair[1]
        return None

